from __future__ import annotations
from typing import Callable

def run_field_patch(
    issue: RemediationIssue,
    fetch_catalog_fields: Callable[[str], dict],       # doc_id → field dict
    fetch_chunk_ids: Callable[[str], list[str]],       # doc_id → chunk_ids
    patch_chunk_fields: Callable[[str, dict], None],   # chunk_id, fields
) -> bool:
    """Patch missing required fields on each chunk from catalog values."""
    try:
        fields = fetch_catalog_fields(issue.doc_id)
        # Only patch fields the catalog has; do not overwrite existing values
        patchable = {
            k: v for k, v in fields.items()
            if k in REQUIRED_CHUNK_FIELDS and v is not None
        }
        if not patchable:
            issue.status = RemediationStatus.ESCALATED
            return False

        chunk_ids = fetch_chunk_ids(issue.doc_id)
        for cid in chunk_ids:
            patch_chunk_fields(cid, patchable)

        issue.mark_resolved(f"patched {len(patchable)} fields on {len(chunk_ids)} chunks")
        return True
    except Exception as exc:
        issue.status = RemediationStatus.ESCALATED
        return False

# Required fields set — imported from quality checker module in production
REQUIRED_CHUNK_FIELDS = {
    "doc_id", "chunk_id", "content_class",
    "source_updated_at", "ingested_at",
    "classification_label", "permitted_apps", "embedding_model",
}

from __future__ import annotations

AUTO_REMEDIABLE: set[IssueType] = {
    IssueType.STALE_SOURCE,
    IssueType.INGESTION_LAG,
    IssueType.EMBEDDING_DRIFT,
    IssueType.CHUNK_COUNT_LOW,
    IssueType.COVERAGE_LOW,
}

FIELD_PATCHABLE: set[IssueType] = {
    IssueType.MISSING_FIELD,
}

REQUIRES_STEWARD: set[IssueType] = {
    IssueType.SOURCE_UNREACHABLE,
    IssueType.CLASSIFICATION_MISSING,
}

def route_and_remediate(
    issue: RemediationIssue,
    re_ingest_fn,
    field_patch_fn,
    notify_steward_fn,
) -> None:
    """Dispatch the issue to the appropriate remediation handler."""
    issue.status = RemediationStatus.IN_PROGRESS

    if issue.issue_type in AUTO_REMEDIABLE:
        result = re_ingest_fn(issue)
        if not result.success:
            notify_steward_fn(issue, reason="re-ingestion failed after retries")

    elif issue.issue_type in FIELD_PATCHABLE:
        ok = field_patch_fn(issue)
        if not ok:
            notify_steward_fn(issue, reason="catalog missing required field values")

    elif issue.issue_type in REQUIRES_STEWARD:
        issue.status = RemediationStatus.ESCALATED
        notify_steward_fn(issue, reason=f"manual action required: {issue.issue_type.value}")
